    76→		return eaddr;
    77→	}
    78→
    79→	mib[0] = CTL_NET;
    80→	mib[1] = PF_ROUTE;
    81→	mib[3] = 0;
    82→	mib[3] = 0;
    83→	mib[4] = NET_RT_IFLIST;
    84→	mib[5] = 0;
    85→
    86→	if (sysctl(mib, sizeof(mib), NULL, &needed, NULL, 0) < 0) {
    87→		return NULL;
    88→	}
    89→
    90→	buf = malloc(needed);
    91→	if( buf == NULL ) return NULL;
    92→
    93→	if (sysctl(mib, sizeof(mib), buf, &needed, NULL, 0) < 0) {
    94→		free(buf);
    95→		return NULL;
    96→	}
