   162→				(unsigned char *)sdl->sdl_data + sdl->sdl_nlen,
   163→				sizeof(eaddr));
   164→			return eaddr;
   165→		}
   166→	}
   167→
   168→	return NULL;
   169→
   170→#else
   171→	if (memcmp(eaddr, zero, sizeof(eaddr)) == 0) {
   172→		/* XXX - who knows? */
   173→		lutil_entropy( eaddr, sizeof(eaddr) );
